// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

import "@openzeppelin/contracts/token/ERC20/IERC20.sol";
import "@openzeppelin/contracts/token/ERC20/utils/SafeERC20.sol";
import "@openzeppelin/contracts/access/Ownable.sol";
import "@openzeppelin/contracts/utils/ReentrancyGuard.sol";

/**
 * @title SAFEStaking
 * @dev Staking contract for $SAFE tokens
 *
 * Tiers and Benefits:
 * - Bronze (100+): 0.5% weekly APY
 * - Silver (500+): 0.75% weekly APY
 * - Gold (1000+): 1% weekly APY
 * - Platinum (2500+): 1.25% weekly APY
 * - Diamond (5000+): 2% weekly APY
 *
 * Features:
 * - 7-day unstaking cooldown
 * - Weekly reward distribution
 * - Vote power multiplier based on stake
 */
contract SAFEStaking is Ownable, ReentrancyGuard {
    using SafeERC20 for IERC20;

    IERC20 public immutable safeToken;

    // Staking info per user
    struct StakeInfo {
        uint256 amount;
        uint256 stakedAt;
        uint256 lastRewardClaim;
    }

    // Unstaking request
    struct UnstakeRequest {
        uint256 amount;
        uint256 unlockTime;
    }

    // User stakes (can have multiple)
    mapping(address => StakeInfo[]) public userStakes;
    // Pending unstake requests
    mapping(address => UnstakeRequest[]) public unstakeRequests;
    // Total staked per user
    mapping(address => uint256) public totalStakedByUser;

    // Global stats
    uint256 public totalStaked;
    uint256 public totalStakers;

    // Tier thresholds
    uint256 public constant BRONZE_THRESHOLD = 100 * 10**18;
    uint256 public constant SILVER_THRESHOLD = 500 * 10**18;
    uint256 public constant GOLD_THRESHOLD = 1000 * 10**18;
    uint256 public constant PLATINUM_THRESHOLD = 2500 * 10**18;
    uint256 public constant DIAMOND_THRESHOLD = 5000 * 10**18;

    // APY rates (basis points per week, 100 = 1%)
    uint256 public constant BRONZE_APY = 50;    // 0.5%
    uint256 public constant SILVER_APY = 75;    // 0.75%
    uint256 public constant GOLD_APY = 100;     // 1%
    uint256 public constant PLATINUM_APY = 125; // 1.25%
    uint256 public constant DIAMOND_APY = 200;  // 2%

    // Unstaking cooldown (7 days)
    uint256 public constant UNSTAKE_COOLDOWN = 7 days;

    // Minimum stake
    uint256 public constant MIN_STAKE = 100 * 10**18;

    // Max weekly reward per user (200 SAFE)
    uint256 public constant MAX_WEEKLY_REWARD = 200 * 10**18;

    // Events
    event Staked(address indexed user, uint256 amount, uint256 totalStaked);
    event UnstakeRequested(address indexed user, uint256 amount, uint256 unlockTime);
    event Withdrawn(address indexed user, uint256 amount);
    event RewardsClaimed(address indexed user, uint256 amount);
    event TierChanged(address indexed user, uint8 newTier);

    constructor(address _safeToken) Ownable(msg.sender) {
        require(_safeToken != address(0), "Invalid token address");
        safeToken = IERC20(_safeToken);
    }

    /**
     * @dev Stake SAFE tokens
     */
    function stake(uint256 amount) external nonReentrant {
        require(amount >= MIN_STAKE, "Below minimum stake");

        // Transfer tokens to contract
        safeToken.safeTransferFrom(msg.sender, address(this), amount);

        // Track if new staker
        bool isNewStaker = totalStakedByUser[msg.sender] == 0;

        // Create stake record
        userStakes[msg.sender].push(StakeInfo({
            amount: amount,
            stakedAt: block.timestamp,
            lastRewardClaim: block.timestamp
        }));

        // Update totals
        totalStakedByUser[msg.sender] += amount;
        totalStaked += amount;

        if (isNewStaker) {
            totalStakers++;
        }

        // Check tier change
        uint8 tier = getTier(msg.sender);
        emit TierChanged(msg.sender, tier);
        emit Staked(msg.sender, amount, totalStakedByUser[msg.sender]);
    }

    /**
     * @dev Request unstake (starts 7-day cooldown)
     */
    function requestUnstake(uint256 stakeIndex) external nonReentrant {
        require(stakeIndex < userStakes[msg.sender].length, "Invalid stake index");

        StakeInfo storage stakeInfo = userStakes[msg.sender][stakeIndex];
        require(stakeInfo.amount > 0, "Nothing to unstake");

        uint256 amount = stakeInfo.amount;
        uint256 unlockTime = block.timestamp + UNSTAKE_COOLDOWN;

        // Create unstake request
        unstakeRequests[msg.sender].push(UnstakeRequest({
            amount: amount,
            unlockTime: unlockTime
        }));

        // Clear the stake
        stakeInfo.amount = 0;

        // Update totals (still counts as staked until withdrawn)
        totalStakedByUser[msg.sender] -= amount;
        totalStaked -= amount;

        // Check tier change
        uint8 tier = getTier(msg.sender);
        emit TierChanged(msg.sender, tier);
        emit UnstakeRequested(msg.sender, amount, unlockTime);
    }

    /**
     * @dev Withdraw all unlocked unstake requests
     */
    function withdraw() external nonReentrant {
        uint256 totalWithdraw = 0;
        UnstakeRequest[] storage requests = unstakeRequests[msg.sender];

        for (uint256 i = 0; i < requests.length; i++) {
            if (requests[i].unlockTime <= block.timestamp && requests[i].amount > 0) {
                totalWithdraw += requests[i].amount;
                requests[i].amount = 0;
            }
        }

        require(totalWithdraw > 0, "Nothing to withdraw");

        // Transfer tokens back
        safeToken.safeTransfer(msg.sender, totalWithdraw);

        // Check if user has completely exited
        if (totalStakedByUser[msg.sender] == 0) {
            totalStakers--;
        }

        emit Withdrawn(msg.sender, totalWithdraw);
    }

    /**
     * @dev Claim staking rewards
     */
    function claimRewards() external nonReentrant {
        uint256 totalReward = calculatePendingRewards(msg.sender);
        require(totalReward > 0, "No rewards to claim");

        // Cap at max weekly reward
        if (totalReward > MAX_WEEKLY_REWARD) {
            totalReward = MAX_WEEKLY_REWARD;
        }

        // Update last claim time for all stakes
        StakeInfo[] storage stakes = userStakes[msg.sender];
        for (uint256 i = 0; i < stakes.length; i++) {
            if (stakes[i].amount > 0) {
                stakes[i].lastRewardClaim = block.timestamp;
            }
        }

        // Transfer rewards (requires contract to have reward tokens)
        safeToken.safeTransfer(msg.sender, totalReward);

        emit RewardsClaimed(msg.sender, totalReward);
    }

    /**
     * @dev Calculate pending rewards for a user
     */
    function calculatePendingRewards(address user) public view returns (uint256) {
        StakeInfo[] storage stakes = userStakes[user];
        uint256 totalReward = 0;

        for (uint256 i = 0; i < stakes.length; i++) {
            if (stakes[i].amount > 0) {
                uint256 timeStaked = block.timestamp - stakes[i].lastRewardClaim;
                uint256 weeks_ = timeStaked / 1 weeks;

                if (weeks_ > 0) {
                    uint256 apy = getAPYForAmount(stakes[i].amount);
                    uint256 reward = (stakes[i].amount * apy * weeks_) / 10000;
                    totalReward += reward;
                }
            }
        }

        return totalReward;
    }

    /**
     * @dev Get user's tier (0-5)
     */
    function getTier(address user) public view returns (uint8) {
        uint256 staked = totalStakedByUser[user];

        if (staked >= DIAMOND_THRESHOLD) return 5;
        if (staked >= PLATINUM_THRESHOLD) return 4;
        if (staked >= GOLD_THRESHOLD) return 3;
        if (staked >= SILVER_THRESHOLD) return 2;
        if (staked >= BRONZE_THRESHOLD) return 1;
        return 0;
    }

    /**
     * @dev Get APY rate for a stake amount (basis points)
     */
    function getAPYForAmount(uint256 amount) public pure returns (uint256) {
        if (amount >= DIAMOND_THRESHOLD) return DIAMOND_APY;
        if (amount >= PLATINUM_THRESHOLD) return PLATINUM_APY;
        if (amount >= GOLD_THRESHOLD) return GOLD_APY;
        if (amount >= SILVER_THRESHOLD) return SILVER_APY;
        if (amount >= BRONZE_THRESHOLD) return BRONZE_APY;
        return 0;
    }

    /**
     * @dev Get vote power multiplier (10000 = 1x, 25000 = 2.5x)
     */
    function getVotePower(address user) external view returns (uint256) {
        uint8 tier = getTier(user);

        // Base 10000 (1x) + tier bonus
        if (tier == 5) return 25000; // 2.5x (diamond)
        if (tier == 4) return 22000; // 2.2x (platinum)
        if (tier == 3) return 18000; // 1.8x (gold)
        if (tier == 2) return 15000; // 1.5x (silver)
        if (tier == 1) return 12000; // 1.2x (bronze)
        return 10000; // 1x (no stake)
    }

    /**
     * @dev Get user stake info
     */
    function getUserStakes(address user) external view returns (StakeInfo[] memory) {
        return userStakes[user];
    }

    /**
     * @dev Get user unstake requests
     */
    function getUnstakeRequests(address user) external view returns (UnstakeRequest[] memory) {
        return unstakeRequests[user];
    }

    /**
     * @dev Fund reward pool (owner only)
     */
    function fundRewardPool(uint256 amount) external onlyOwner {
        safeToken.safeTransferFrom(msg.sender, address(this), amount);
    }

    /**
     * @dev Emergency withdraw (owner only)
     */
    function emergencyWithdraw(uint256 amount) external onlyOwner {
        safeToken.safeTransfer(msg.sender, amount);
    }
}

