// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

import "@openzeppelin/contracts/token/ERC20/ERC20.sol";
import "@openzeppelin/contracts/token/ERC20/extensions/ERC20Burnable.sol";
import "@openzeppelin/contracts/access/Ownable.sol";

/**
 * @title SAFEToken
 * @dev $SAFE Token for SafeScoring platform
 *
 * Tokenomics:
 * - Total Supply: 100,000,000 SAFE (100M)
 * - Decimals: 18
 *
 * Distribution:
 * - 40% Community Rewards (staking, verifications)
 * - 30% Treasury (development, partnerships)
 * - 20% Team (vested 2 years)
 * - 10% Initial Liquidity
 */
contract SAFEToken is ERC20, ERC20Burnable, Ownable {
    uint256 public constant MAX_SUPPLY = 100_000_000 * 10**18; // 100M tokens

    // Addresses for distribution
    address public communityRewardsWallet;
    address public treasuryWallet;
    address public teamWallet;
    address public liquidityWallet;

    // Track minted amounts per category
    uint256 public communityMinted;
    uint256 public treasuryMinted;
    uint256 public teamMinted;
    uint256 public liquidityMinted;

    // Recycling pool - tokens spent in shop come back here
    uint256 public recycledPool;

    // Allocation limits
    uint256 public constant COMMUNITY_ALLOCATION = 40_000_000 * 10**18; // 40%
    uint256 public constant TREASURY_ALLOCATION = 30_000_000 * 10**18;  // 30%
    uint256 public constant TEAM_ALLOCATION = 20_000_000 * 10**18;      // 20%
    uint256 public constant LIQUIDITY_ALLOCATION = 10_000_000 * 10**18; // 10%

    // Events
    event WalletsUpdated(
        address communityRewards,
        address treasury,
        address team,
        address liquidity
    );
    event CommunityRewardsMinted(address indexed to, uint256 amount);
    event TokensRecycled(address indexed from, uint256 amount);
    event RecycledRewardsMinted(address indexed to, uint256 amount);

    constructor(
        address _communityRewardsWallet,
        address _treasuryWallet,
        address _teamWallet,
        address _liquidityWallet
    ) ERC20("SafeScoring Token", "SAFE") Ownable(msg.sender) {
        require(_communityRewardsWallet != address(0), "Invalid community wallet");
        require(_treasuryWallet != address(0), "Invalid treasury wallet");
        require(_teamWallet != address(0), "Invalid team wallet");
        require(_liquidityWallet != address(0), "Invalid liquidity wallet");

        communityRewardsWallet = _communityRewardsWallet;
        treasuryWallet = _treasuryWallet;
        teamWallet = _teamWallet;
        liquidityWallet = _liquidityWallet;

        // Mint initial liquidity allocation
        _mint(_liquidityWallet, LIQUIDITY_ALLOCATION);
        liquidityMinted = LIQUIDITY_ALLOCATION;
    }

    /**
     * @dev Mint tokens for community rewards (staking, verifications)
     * First uses original allocation, then recycled pool
     * Only owner can call this
     */
    function mintCommunityRewards(address to, uint256 amount) external onlyOwner {
        uint256 remainingAllocation = COMMUNITY_ALLOCATION - communityMinted;

        if (amount <= remainingAllocation) {
            // Use original allocation
            communityMinted += amount;
            _mint(to, amount);
        } else if (remainingAllocation > 0) {
            // Use remaining allocation + recycled pool
            uint256 fromRecycled = amount - remainingAllocation;
            require(fromRecycled <= recycledPool, "Exceeds available tokens");

            communityMinted += remainingAllocation;
            recycledPool -= fromRecycled;
            _mint(to, amount);
        } else {
            // Only use recycled pool
            require(amount <= recycledPool, "Exceeds recycled pool");
            recycledPool -= amount;
            _mint(to, amount);
            emit RecycledRewardsMinted(to, amount);
        }

        emit CommunityRewardsMinted(to, amount);
    }

    /**
     * @dev Recycle tokens (burn and add to recycled pool)
     * Called when users spend tokens in the shop
     * Anyone can call this on their own tokens
     */
    function recycleTokens(uint256 amount) external {
        require(balanceOf(msg.sender) >= amount, "Insufficient balance");
        _burn(msg.sender, amount);
        recycledPool += amount;
        emit TokensRecycled(msg.sender, amount);
    }

    /**
     * @dev Admin function to recycle tokens from shop wallet
     * Only owner can call this
     */
    function recycleFromShop(address shopWallet, uint256 amount) external onlyOwner {
        require(balanceOf(shopWallet) >= amount, "Insufficient balance in shop");
        _burn(shopWallet, amount);
        recycledPool += amount;
        emit TokensRecycled(shopWallet, amount);
    }

    /**
     * @dev Mint tokens to treasury
     * Only owner can call this
     */
    function mintToTreasury(uint256 amount) external onlyOwner {
        require(treasuryMinted + amount <= TREASURY_ALLOCATION, "Exceeds treasury allocation");
        treasuryMinted += amount;
        _mint(treasuryWallet, amount);
    }

    /**
     * @dev Mint tokens to team (should be vested)
     * Only owner can call this
     */
    function mintToTeam(uint256 amount) external onlyOwner {
        require(teamMinted + amount <= TEAM_ALLOCATION, "Exceeds team allocation");
        teamMinted += amount;
        _mint(teamWallet, amount);
    }

    /**
     * @dev Update wallet addresses
     * Only owner can call this
     */
    function updateWallets(
        address _communityRewardsWallet,
        address _treasuryWallet,
        address _teamWallet,
        address _liquidityWallet
    ) external onlyOwner {
        if (_communityRewardsWallet != address(0)) {
            communityRewardsWallet = _communityRewardsWallet;
        }
        if (_treasuryWallet != address(0)) {
            treasuryWallet = _treasuryWallet;
        }
        if (_teamWallet != address(0)) {
            teamWallet = _teamWallet;
        }
        if (_liquidityWallet != address(0)) {
            liquidityWallet = _liquidityWallet;
        }

        emit WalletsUpdated(
            communityRewardsWallet,
            treasuryWallet,
            teamWallet,
            liquidityWallet
        );
    }

    /**
     * @dev Get remaining mintable amounts
     */
    function getRemainingAllocations() external view returns (
        uint256 communityRemaining,
        uint256 treasuryRemaining,
        uint256 teamRemaining,
        uint256 liquidityRemaining,
        uint256 recycledAvailable
    ) {
        return (
            COMMUNITY_ALLOCATION - communityMinted,
            TREASURY_ALLOCATION - treasuryMinted,
            TEAM_ALLOCATION - teamMinted,
            LIQUIDITY_ALLOCATION - liquidityMinted,
            recycledPool
        );
    }

    /**
     * @dev Get total available for community rewards (allocation + recycled)
     */
    function getAvailableForRewards() external view returns (uint256) {
        return (COMMUNITY_ALLOCATION - communityMinted) + recycledPool;
    }
}

